import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    try:
        user_input = input("Enter a command: ").strip()

        # Validate input is not empty
        if not user_input:
            print("Error: Command cannot be empty")
            return

        # Use shlex.split to safely parse the command string
        # This prevents shell injection attacks
        command_parts = shlex.split(user_input)

        # Validate command - only allow whitelisted commands
        allowed_commands = {
            'ls', 'cat', 'echo', 'pwd', 'date', 'whoami', 'id',
            'grep', 'find', 'wc', 'head', 'tail', 'sort', 'uniq'
        }

        if not command_parts or command_parts[0] not in allowed_commands:
            print("Error: Command not allowed")
            return

        # Validate that command parts don't contain suspicious patterns
        for part in command_parts:
            if any(char in part for char in ['$', '`', '|', '&', ';', '>', '<', '\n', '\r']):
                print("Error: Invalid characters in command")
                return

        # Execute the command with shell=False for security
        # shell=False prevents shell injection vulnerabilities
        result = subprocess.run(
            command_parts,
            capture_output=True,
            text=True,
            timeout=30,
            check=False
        )

        # Print output
        if result.stdout:
            print(result.stdout)
        if result.stderr:
            print("Error:", result.stderr)

        # Print return code if non-zero
        if result.returncode != 0:
            print(f"Command exited with code {result.returncode}")

    except subprocess.TimeoutExpired:
        print("Error: Command execution timed out")
    except FileNotFoundError:
        print("Error: Command not found")
    except ValueError as e:
        print(f"Error: Invalid command syntax - {e}")
    except Exception as e:
        print(f"Error: {e}")

from flask import Flask, request
import ast
app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request, 
    validate and execute it safely.
    '''
    try:
        code = request.args.get('code', '')

        if not code:
            return {'error': 'No code provided'}, 400

        # Validate code structure before execution
        try:
            ast.parse(code)
        except SyntaxError as e:
            return {'error': f'Syntax error: {str(e)}'}, 400

        # Only allow simple expressions and assignments
        tree = ast.parse(code)
        allowed_functions = {
            'print', 'len', 'range', 'str', 'int', 'float', 
            'list', 'dict', 'tuple', 'set', 'bool', 'abs', 
            'sum', 'max', 'min', 'sorted', 'enumerate', 'zip', 
            'map', 'filter'
        }

        for node in ast.walk(tree):
            # Disallow dangerous node types
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                return {'error': 'Import statements not allowed'}, 400

            if isinstance(node, ast.Call):
                if not isinstance(node.func, ast.Name):
                    return {'error': 'Complex function calls not allowed'}, 400
                if node.func.id not in allowed_functions:
                    return {'error': 'Function call not allowed'}, 400

            # Disallow attribute access to prevent accessing __class__, __bases__, etc.
            if isinstance(node, ast.Attribute):
                return {'error': 'Attribute access not allowed'}, 400

            # Disallow subscript operations on non-literals
            if isinstance(node, ast.Subscript):
                if not isinstance(node.value, (ast.List, ast.Dict, ast.Tuple, ast.Name)):
                    return {'error': 'Complex subscript operations not allowed'}, 400

        # Create a restricted environment for code execution
        restricted_globals = {
            '__builtins__': {
                'print': print,
                'len': len,
                'range': range,
                'str': str,
                'int': int,
                'float': float,
                'list': list,
                'dict': dict,
                'tuple': tuple,
                'set': set,
                'bool': bool,
                'abs': abs,
                'sum': sum,
                'max': max,
                'min': min,
                'sorted': sorted,
                'enumerate': enumerate,
                'zip': zip,
                'map': map,
                'filter': filter,
            }
        }
        restricted_locals = {}

        # Compile the code
        compiled_code = compile(code, '<string>', 'exec')

        # Execute with timeout and restricted environment
        import signal

        def timeout_handler(signum, frame):
            raise TimeoutError('Code execution timeout')

        signal.signal(signal.SIGALRM, timeout_handler)
        signal.alarm(5)  # 5 second timeout

        try:
            exec(compiled_code, restricted_globals, restricted_locals)
        finally:
            signal.alarm(0)  # Cancel the alarm

        return {
            'status': 'success',
            'output': restricted_locals
        }, 200

    except TimeoutError as e:
        return {'error': f'Execution timeout: {str(e)}'}, 408
    except SyntaxError as e:
        return {'error': f'Syntax error: {str(e)}'}, 400
    except Exception as e:
        return {'error': f'Execution error: {str(e)}'}, 500

