    'list', 'dict', 'tuple', 'set', 'bool', 'abs', 
    'sum', 'max', 'min', 'sorted', 'enumerate', 'zip', 
    'map', 'filter'
}

# Safe built-in operations
ALLOWED_OPERATORS = {
    ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow,
    ast.FloorDiv, ast.LShift, ast.RShift, ast.BitOr, ast.BitXor,
    ast.BitAnd, ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
    ast.Is, ast.IsNot, ast.In, ast.NotIn, ast.And, ast.Or, ast.Not,
    ast.UAdd, ast.USub, ast.Invert
}

class SafeEvaluator(ast.NodeVisitor):
    """Safely evaluate AST nodes without using exec()"""

    def __init__(self):
        self.variables = {}

    def visit_Constant(self, node):
        return node.value

    def visit_Num(self, node):
        return node.n

    def visit_Str(self, node):
        return node.s

    def visit_List(self, node):
        return [self.visit(elt) for elt in node.elts]

    def visit_Tuple(self, node):
        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Dict(self, node):
        return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

    def visit_Set(self, node):
        return {self.visit(elt) for elt in node.elts}

    def visit_Name(self, node):
        if node.id in self.variables:
            return self.variables[node.id]
        raise NameError(f"Name '{node.id}' is not defined")

    def visit_Call(self, node):
        if not isinstance(node.func, ast.Name):
            raise ValueError("Complex function calls not allowed")

        func_name = node.func.id
        if func_name not in ALLOWED_FUNCTIONS:
            raise ValueError(f"Function '{func_name}' not allowed")

        func = eval(func_name, {"__builtins__": {}})
        args = [self.visit(arg) for arg in node.args]
        kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}

        return func(*args, **kwargs)

    def visit_BinOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise ValueError("Operation not allowed")

        left = self.visit(node.left)
        right = self.visit(node.right)
        op_map = {
            ast.Add: operator.add, ast.Sub: operator.sub,
            ast.Mult: operator.mul, ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv, ast.Mod: operator.mod,
            ast.Pow: operator.pow, ast.LShift: operator.lshift,
            ast.RShift: operator.rshift, ast.BitOr: operator.or_,
            ast.BitXor: operator.xor, ast.BitAnd: operator.and_,
        }
        return op_map[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise ValueError("Operation not allowed")

        operand = self.visit(node.operand)
        op_map = {
            ast.UAdd: operator.pos, ast.USub: operator.neg,
            ast.Not: operator.not_, ast.Invert: operator.invert,
        }
        return op_map[type(node.op)](operand)

    def visit_Compare(self, node):
        left = self.visit(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            if type(op) not in ALLOWED_OPERATORS:
                raise ValueError("Comparison not allowed")
            right = self.visit(comparator)
            op_map = {
                ast.Eq: operator.eq, ast.NotEq: operator.ne,
                ast.Lt: operator.lt, ast.LtE: operator.le,
                ast.Gt: operator.gt, ast.GtE: operator.ge,
                ast.Is: operator.is_, ast.IsNot: operator.is_not,
                ast.In: lambda x, y: x in y,
                ast.NotIn: lambda x, y: x not in y,
            }
            if not op_map[type(op)](left, right):
                return False
            left = right
        return True

    def visit_Subscript(self, node):
        value = self.visit(node.value)
        index = self.visit(node.slice)
        return value[index]

    def visit_Index(self, node):
        return self.visit(node.value)

    def visit_BoolOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise ValueError("Operation not allowed")

        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = result and self.visit(value)
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = result or self.visit(value)
            return result

    def visit_Expr(self, node):
        return self.visit(node.value)

    def visit_Module(self, node):
        result = None
        for stmt in node.body:
            result = self.visit(stmt)
        return result

    def generic_visit(self, node):
        raise ValueError(f"Node type '{type(node).__name__}' not allowed")

