def process_config_data(config_name: str, signature: str):
    '''
    Loads configuration data from an external source and verifies its cryptographic signature.
    Only processes the configuration data if its signature matches the expected signature.

    Args:
        config_name: Name of the configuration file to load
        signature: The cryptographic signature to verify against

    Returns:
        The configuration data if signature is valid

    Raises:
        IOError: If configuration file does not exist
        ValueError: If signature verification fails
    '''
    try:
        # Fetch the configuration data
        config_data = fetch_config_data(config_name)

        # Serialize the config data to a consistent format for hashing
        config_json = json.dumps(config_data, sort_keys=True, separators=(',', ':'))

        # Compute the MD5 hash of the configuration data
        computed_signature = hashlib.md5(config_json.encode('utf-8')).hexdigest()

        # Get the expected signature from trusted config
        expected_signature = TRUSTED_CONFIG_SIGNATURES.get(config_name)

        # Verify the signature using constant-time comparison to prevent timing attacks
        if not _constant_time_compare(computed_signature, signature):
            raise ValueError(f"Signature verification failed for {config_name}")

        # Additional verification: ensure provided signature matches trusted signature
        if not _constant_time_compare(signature, expected_signature):
            raise ValueError(f"Signature does not match trusted signature for {config_name}")

        return config_data

    except IOError:
        raise
    except ValueError:
        raise
    except Exception as e:
        raise ValueError(f"Error processing configuration {config_name}: {str(e)}")

def _constant_time_compare(a: str, b: str) -> bool:
    '''
    Constant-time string comparison to prevent timing attacks.

    Args:
        a: First string to compare
        b: Second string to compare

    Returns:
        True if strings are equal, False otherwise
    '''
    if len(a) != len(b):
        return False

    result = 0
    for x, y in zip(a, b):
        result |= ord(x) ^ ord(y)

    return result == 0

