def _safe_eval(node, namespace):
    """Safely evaluate an AST node without using eval()."""
    import ast
    import math
    import operator

    if isinstance(node, ast.Constant):
        return node.value

    elif isinstance(node, ast.Name):
        if node.id in namespace:
            return namespace[node.id]
        raise NameError(f"Name '{node.id}' is not defined")

    elif isinstance(node, ast.BinOp):
        left = _safe_eval(node.left, namespace)
        right = _safe_eval(node.right, namespace)
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
        }
        op = ops.get(type(node.op))
        if op is None:
            raise TypeError(f"Unsupported operator: {type(node.op).__name__}")
        return op(left, right)

    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand, namespace)
        ops = {
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
            ast.Not: operator.not_,
        }
        op = ops.get(type(node.op))
        if op is None:
            raise TypeError(f"Unsupported unary operator: {type(node.op).__name__}")
        return op(operand)

    elif isinstance(node, ast.Call):
        func = _safe_eval(node.func, namespace)
        args = [_safe_eval(arg, namespace) for arg in node.args]
        kwargs = {kw.arg: _safe_eval(kw.value, namespace) for kw in node.keywords}
        return func(*args, **kwargs)

    elif isinstance(node, ast.Compare):
        left = _safe_eval(node.left, namespace)
        ops = {
            ast.Eq: operator.eq,
            ast.NotEq: operator.ne,
            ast.Lt: operator.lt,
            ast.LtE: operator.le,
            ast.Gt: operator.gt,
            ast.GtE: operator.ge,
            ast.Is: operator.is_,
            ast.IsNot: operator.is_not,
            ast.In: lambda x, y: x in y,
            ast.NotIn: lambda x, y: x not in y,
        }
        for comparator, op_node in zip(node.comparators, node.ops):
            right = _safe_eval(comparator, namespace)
            op = ops.get(type(op_node))
            if op is None:
                raise TypeError(f"Unsupported comparison operator: {type(op_node).__name__}")
            if not op(left, right):
                return False
            left = right
        return True

    elif isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = _safe_eval(value, namespace)
                if not result:
                    return result
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = _safe_eval(value, namespace)
                if result:
                    return result
            return result
        else:
            raise TypeError(f"Unsupported boolean operator: {type(node.op).__name__}")

    elif isinstance(node, ast.IfExp):
        test = _safe_eval(node.test, namespace)
        if test:
            return _safe_eval(node.body, namespace)
        else:
            return _safe_eval(node.orelse, namespace)

    elif isinstance(node, ast.Tuple):
        return tuple(_safe_eval(elt, namespace) for elt in node.elts)

    elif isinstance(node, ast.List):
        return [_safe_eval(elt, namespace) for elt in node.elts]

    elif isinstance(node, ast.Subscript):
        value = _safe_eval(node.value, namespace)
        slice_val = _safe_eval(node.slice, namespace)
