def _evaluate_safe_ast(node):
    """
    Safely evaluate an AST node that has been validated by _is_safe_ast.
    Does not use eval() - instead manually evaluates the AST.
    """
    import ast
    import operator

    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Num):
        # For Python < 3.8 compatibility
        return node.n

    if isinstance(node, ast.BinOp):
        left = _evaluate_safe_ast(node.left)
        right = _evaluate_safe_ast(node.right)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            return left / right
        elif isinstance(node.op, ast.Mod):
            return left % right
        elif isinstance(node.op, ast.FloorDiv):
            return left // right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError("Unsupported binary operation")

    if isinstance(node, ast.UnaryOp):
        operand = _evaluate_safe_ast(node.operand)

        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
